let zTop = 10, activeWin = null;

function bringToFront(id) {
  const el = document.getElementById(id);
  if (!el) return;
  zTop++;
  el.style.zIndex = zTop;
  document.querySelectorAll('.win').forEach(w => w.classList.add('inactive'));
  el.classList.remove('inactive');
  activeWin = id;
  updateTaskbar();
}

function openWin(name) {
  const w = wins[name];
  if (!w) return;
  const el = document.getElementById(w.el);
  el.style.display = 'block';
  w.open = true;
  w.minimized = false;
  bringToFront(w.el);
  updateTaskbar();
}

function closeWin(name) {
  const w = wins[name];
  if (!w) return;
  document.getElementById(w.el).style.display = 'none';
  w.open = false;
  w.minimized = false;
  updateTaskbar();
}

function minimizeWin(name) {
  const w = wins[name];
  if (!w) return;
  document.getElementById(w.el).style.display = 'none';
  w.minimized = true;
  updateTaskbar();
}

function updateTaskbar() {
  const bar = document.getElementById('taskbar-tasks');
  bar.innerHTML = '';
  Object.entries(wins).forEach(([name, w]) => {
    if (!w.open && !w.minimized) return;
    const btn = document.createElement('div');
    btn.className = 'taskbar-btn' + (activeWin === w.el && !w.minimized ? ' active-win' : '');
    btn.textContent = w.label;
    btn.onclick = () => {
      if (!w.minimized && activeWin === w.el) { minimizeWin(name); }
      else { openWin(name); }
    };
    bar.appendChild(btn);
  });
}

document.querySelectorAll('.win').forEach(w => {
  w.addEventListener('mousedown', () => bringToFront(w.id));
});

// ─── Project detail opener ───────────────────────────────────────────────────
let currentProjImages = [];
let currentImgIdx = 0;

function openProject(key) {
  const data = projectData[key];
  if (!data) return;
  document.getElementById('proj-detail-title').textContent = data.title + ' — Explorer';
  document.getElementById('proj-detail-body').innerHTML = data.content;
  document.getElementById('proj-detail-status').textContent = data.status;
  wins.projdetail.label = data.title;

  // Handle images tab
  currentProjImages = data.images || [];
  const tabImages = document.getElementById('tab-images');
  if (currentProjImages.length > 0) {
    tabImages.style.display = '';
    currentImgIdx = 0;
    renderImg();
  } else {
    tabImages.style.display = 'none';
  }

  // Always open on Details tab
  switchProjTab('details');
  openWin('projdetail');
  document.getElementById('proj-detail-body').scrollTop = 0;
}

function switchProjTab(tab) {
  document.querySelectorAll('.proj-tab').forEach(t => t.classList.remove('active'));
  document.querySelectorAll('.proj-tab-panel').forEach(p => p.classList.remove('active'));
  if (tab === 'details') {
    document.querySelectorAll('.proj-tab')[0].classList.add('active');
    document.getElementById('panel-details').classList.add('active');
    document.getElementById('proj-detail-status2').textContent = 'Scroll to read more';
  } else {
    document.querySelectorAll('.proj-tab')[1].classList.add('active');
    document.getElementById('panel-images').classList.add('active');
    document.getElementById('proj-detail-status2').textContent = currentProjImages.length + ' image(s)';
    renderImg();
  }
}

function renderImg() {
  if (!currentProjImages.length) return;
  const img = currentProjImages[currentImgIdx];
  document.getElementById('img-viewer-img').src = img.src;
  document.getElementById('img-viewer-img').alt = img.caption;
  document.getElementById('img-viewer-caption').textContent = img.caption;
  document.getElementById('img-nav-label').textContent = 'Image ' + (currentImgIdx + 1) + ' / ' + currentProjImages.length;
}

function imgNav(dir) {
  currentImgIdx = (currentImgIdx + dir + currentProjImages.length) % currentProjImages.length;
  renderImg();
}

// ─── Drag ────────────────────────────────────────────────────────────────────
let dragging = null, dragOffX = 0, dragOffY = 0;
function startDrag(e, id) {
  // Don't drag on mobile
  if (window.innerWidth <= 768) return;
  dragging = document.getElementById(id);
  const rect = dragging.getBoundingClientRect();
  dragOffX = e.clientX - rect.left;
  dragOffY = e.clientY - rect.top;
  dragging.classList.add('dragging');
  bringToFront(id);
  e.preventDefault();
}
document.addEventListener('mousemove', e => {
  if (!dragging) return;
  const x = Math.max(0, e.clientX - dragOffX);
  const y = Math.max(0, e.clientY - dragOffY);
  dragging.style.left = x + 'px';
  dragging.style.top = y + 'px';
});
document.addEventListener('mouseup', () => {
  if (dragging) dragging.classList.remove('dragging');
  dragging = null;
});

// ─── Clock ───────────────────────────────────────────────────────────────────
function updateClock() {
  const now = new Date();
  let h = now.getHours(), m = now.getMinutes();
  const ampm = h >= 12 ? 'PM' : 'AM';
  h = h % 12 || 12;
  document.getElementById('clock-time').textContent = h + ':' + String(m).padStart(2,'0') + ' ' + ampm;
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  document.getElementById('clock-date').textContent = months[now.getMonth()] + ' ' + now.getDate();
}
updateClock();
setInterval(updateClock, 10000);

// ─── Start menu ──────────────────────────────────────────────────────────────
function toggleStart() {
  const m = document.getElementById('start-menu');
  const b = document.getElementById('start-btn');
  m.classList.toggle('open');
  b.classList.toggle('open');
}
function closeStart() {
  document.getElementById('start-menu').classList.remove('open');
  document.getElementById('start-btn').classList.remove('open');
}
document.addEventListener('click', e => {
  if (!e.target.closest('.start-menu') && !e.target.closest('#start-btn')) closeStart();
});

