let cdIdx = 0, cdPlaying = false, cdProgress = 0, cdInterval = null, cdShuffleOn = false;

function cdRender() {
  const t = tracks[cdIdx];
  document.getElementById('cd-artist').textContent = t.artist;
  document.getElementById('cd-track').textContent = t.track;
  document.getElementById('cd-count').textContent = 'Track ' + (cdIdx+1) + ' / ' + tracks.length;
  const pct = Math.round(cdProgress);
  document.getElementById('cd-fill').style.width = pct + '%';
  const total = t.dur[0]*60 + t.dur[1];
  const elapsed = Math.round(total * cdProgress / 100);
  const em = Math.floor(elapsed/60), es = elapsed%60;
  document.getElementById('cd-time').textContent = em+':'+String(es).padStart(2,'0')+' / '+t.dur[0]+':'+String(t.dur[1]).padStart(2,'0');
}
// ─── Audio player ────────────────────────────────────────────────────────────
