audioPlayer.addEventListener('ended', () => cdNext());

function ytLoad(autoplay) {
  const t = tracks[cdIdx];
  // Prefer local MP3 if available, fall back to YouTube iframe
  if (t.src) {
    audioPlayer.src = t.src;
    const total = t.dur[0]*60 + t.dur[1];
    audioPlayer.currentTime = Math.round(total * cdProgress / 100);
    if (autoplay) audioPlayer.play().catch(() => {});
  } else if (t.yt) {
    const wrap = document.getElementById('yt-player-wrap');
    const iframe = document.getElementById('yt-iframe');
    const total = t.dur[0]*60 + t.dur[1];
    const start = Math.round(total * cdProgress / 100);
    iframe.src = 'https://www.youtube.com/embed/' + t.yt
      + '?autoplay=1&start=' + start + '&controls=0&rel=0&modestbranding=1';
    wrap.style.width = '200px';
    wrap.style.height = '113px';
    wrap.style.top = '-300px';
    wrap.style.left = '-300px';
  }
}

function ytStop() {
  audioPlayer.pause();
  audioPlayer.currentTime = 0;
  const iframe = document.getElementById('yt-iframe');
  const wrap = document.getElementById('yt-player-wrap');
  if (iframe) iframe.src = '';
  if (wrap) { wrap.style.width = '0'; wrap.style.height = '0'; }
}

function cdToggle() {
  cdPlaying = !cdPlaying;
  const btn = document.getElementById('cd-playbtn');
  const status = document.getElementById('cd-status');
  if (cdPlaying) {
    btn.textContent = '⏸ Pause'; btn.classList.add('active-btn'); status.textContent = 'Playing...';
    ytLoad(true);
    const t = tracks[cdIdx];
    const totalSecs = t.dur[0] * 60 + t.dur[1];
    const tickPct = 100 / (totalSecs * 10); // 100ms ticks, so *10 ticks per second
    cdInterval = setInterval(() => {
      cdProgress += tickPct;
      if (cdProgress >= 100) { cdNext(); return; }
      cdRender();
    }, 100);
  } else {
    btn.textContent = '▶ Play'; btn.classList.remove('active-btn'); status.textContent = 'Paused';
    clearInterval(cdInterval);
    ytStop();
  }
}
function cdStop() {
  cdPlaying = false; clearInterval(cdInterval); cdProgress = 0;
  document.getElementById('cd-playbtn').textContent = '▶ Play';
  document.getElementById('cd-playbtn').classList.remove('active-btn');
  document.getElementById('cd-status').textContent = 'Stopped';
  ytStop();
  cdRender();
}
function cdNext() {
  cdProgress = 0; clearInterval(cdInterval);
  const wasPlaying = cdPlaying; cdPlaying = false;
  cdIdx = cdShuffleOn ? Math.floor(Math.random()*tracks.length) : (cdIdx+1)%tracks.length;
  ytStop(); cdRender();
  if (wasPlaying) { cdPlaying = false; cdToggle(); }
}
function cdPrev() {
  cdProgress = 0; clearInterval(cdInterval);
  const wasPlaying = cdPlaying; cdPlaying = false;
  cdIdx = (cdIdx-1+tracks.length)%tracks.length;
  ytStop(); cdRender();
  if (wasPlaying) { cdPlaying = false; cdToggle(); }
}
function cdShuffle() {
  cdShuffleOn = !cdShuffleOn;
  document.getElementById('cd-shufflebtn').classList.toggle('active-btn', cdShuffleOn);
}
cdRender();

// ─── Error dialog ────────────────────────────────────────────────────────────
const errors = {
  resume:   ['File Not Found',  'resume.pdf could not be located.\n\nPlease contact Mira directly\nto request her resume.'],
  shutdown: ['Shut Down',       'You cannot shut down this portfolio.\n\nMira is always open to work!'],
  default:  ['Access Denied',   'This item cannot be opened.\n\nThe operation requires elevated\npermissions. Please contact Mira.'],
};
function showError(type) {
  const e = errors[type] || errors.default;
  document.getElementById('error-title').textContent = e[0];
  document.getElementById('error-msg').textContent = e[1];
  const el = document.getElementById('win-error');
  el.style.display = 'block';
  bringToFront('win-error');
}


// ─── Paint zoom ──────────────────────────────────────────────────────────────
let paintZoomed = false;
function paintToggleZoom() {
  const img = document.getElementById('paint-img');
  const wrap = document.getElementById('paint-canvas-wrap');
  const lbl = document.getElementById('paint-zoom-label');
  const btn = document.getElementById('paint-zoom-btn');
  paintZoomed = !paintZoomed;
  if (paintZoomed) {
    img.style.width = '520px'; img.style.height = '520px';
    wrap.style.height = '500px';
    lbl.textContent = '175%';
    btn.classList.add('active');
  } else {
    img.style.width = '300px'; img.style.height = '300px';
    wrap.style.height = '320px';
    lbl.textContent = '100%';
    btn.classList.remove('active');
  }
}
// ─── Skill bars ──────────────────────────────────────────────────────────────
function animateSkills() {
  document.querySelectorAll('.skill-fill').forEach(bar => {
    setTimeout(() => { bar.style.width = bar.dataset.w; }, 200);
  });
}
setTimeout(animateSkills, 2800);

// ─── Boot sequence ───────────────────────────────────────────────────────────
const bootMessages = ['Starting Windows...','Loading system files...','Initializing portfolio...','Loading ASPIRE.exe...','Mounting projects...','Welcome, Recruiter!'];
const blocks = document.querySelectorAll('.boot-block');
const bootText = document.getElementById('boot-text');
let bi = 0;
function bootStep() {
  if (bi < blocks.length) {
    blocks[bi].style.display = 'block';
    bootText.textContent = bootMessages[Math.floor(bi * bootMessages.length / blocks.length)];
    bi++;
    setTimeout(bootStep, 120);
  } else {
    bootText.textContent = 'Welcome, Recruiter!';
    setTimeout(() => {
      document.getElementById('boot').style.transition = 'opacity 0.5s';
      document.getElementById('boot').style.opacity = '0';
      setTimeout(() => document.getElementById('boot').style.display = 'none', 500);
      updateTaskbar();
      setTimeout(initClippy, 800);
    }, 500);
  }
}
setTimeout(bootStep, 300);
updateTaskbar();